48: // RESTStorageProvider is a provider of REST storage
49: type RESTStorageProvider struct {
50: 	InformerFactory informers.SharedInformerFactory
51: }
52: 
53: // PostStartHookName is the name of the post-start-hook provided by flow-control storage
54: const PostStartHookName = "priority-and-fairness-config-producer"
55: 
56: // NewRESTStorage creates a new rest storage for flow-control api models.
57: func (p RESTStorageProvider) NewRESTStorage(apiResourceConfigSource serverstorage.APIResourceConfigSource, restOptionsGetter generic.RESTOptionsGetter) (genericapiserver.APIGroupInfo, error) {
58: 	apiGroupInfo := genericapiserver.NewDefaultAPIGroupInfo(flowcontrol.GroupName, legacyscheme.Scheme, legacyscheme.ParameterCodec, legacyscheme.Codecs)
59: 
60: 	if storageMap, err := p.storage(apiResourceConfigSource, restOptionsGetter, flowcontrolapisv1beta3.SchemeGroupVersion); err != nil {
61: 		return genericapiserver.APIGroupInfo{}, err
62: 	} else if len(storageMap) > 0 {
63: 		apiGroupInfo.VersionedResourcesStorageMap[flowcontrolapisv1beta3.SchemeGroupVersion.Version] = storageMap
64: 	}
65: 
66: 	if storageMap, err := p.storage(apiResourceConfigSource, restOptionsGetter, flowcontrolapisv1.SchemeGroupVersion); err != nil {
67: 		return genericapiserver.APIGroupInfo{}, err
68: 	} else if len(storageMap) > 0 {
69: 		apiGroupInfo.VersionedResourcesStorageMap[flowcontrolapisv1.SchemeGroupVersion.Version] = storageMap
70: 	}
71: 
72: 	return apiGroupInfo, nil
73: }
74: 
75: func (p RESTStorageProvider) storage(apiResourceConfigSource serverstorage.APIResourceConfigSource, restOptionsGetter generic.RESTOptionsGetter, groupVersion schema.GroupVersion) (map[string]rest.Storage, error) {
76: 	storage := map[string]rest.Storage{}
77: 
78: 	// flow-schema
79: 	if resource := "flowschemas"; apiResourceConfigSource.ResourceEnabled(groupVersion.WithResource(resource)) {
80: 		flowSchemaStorage, flowSchemaStatusStorage, err := flowschemastore.NewREST(restOptionsGetter)
81: 		if err != nil {
82: 			return nil, err
83: 		}
84: 		storage[resource] = flowSchemaStorage
85: 		storage[resource+"/status"] = flowSchemaStatusStorage
86: 	}
87: 
88: 	// priority-level-configuration
89: 	if resource := "prioritylevelconfigurations"; apiResourceConfigSource.ResourceEnabled(groupVersion.WithResource(resource)) {
90: 		priorityLevelConfigurationStorage, priorityLevelConfigurationStatusStorage, err := prioritylevelconfigurationstore.NewREST(restOptionsGetter)
91: 		if err != nil {
92: 			return nil, err
93: 		}
94: 		storage[resource] = priorityLevelConfigurationStorage
95: 		storage[resource+"/status"] = priorityLevelConfigurationStatusStorage
96: 	}
97: 
98: 	return storage, nil
99: }
100: 
101: // GroupName returns group name of the storage
102: func (p RESTStorageProvider) GroupName() string {
103: 	return flowcontrol.GroupName
104: }
105: 
106: // PostStartHook returns the hook func that launches the config provider
107: func (p RESTStorageProvider) PostStartHook() (string, genericapiserver.PostStartHookFunc, error) {
108: 	bce := &bootstrapConfigurationEnsurer{
109: 		informersSynced: []cache.InformerSynced{
110: 			p.InformerFactory.Flowcontrol().V1().PriorityLevelConfigurations().Informer().HasSynced,
111: 			p.InformerFactory.Flowcontrol().V1().FlowSchemas().Informer().HasSynced,
112: 		},
113: 		fsLister:  p.InformerFactory.Flowcontrol().V1().FlowSchemas().Lister(),
114: 		plcLister: p.InformerFactory.Flowcontrol().V1().PriorityLevelConfigurations().Lister(),
115: 	}
116: 	return PostStartHookName, bce.ensureAPFBootstrapConfiguration, nil
117: }
118: 
119: type bootstrapConfigurationEnsurer struct {
120: 	informersSynced []cache.InformerSynced
121: 	fsLister        flowcontrollisters.FlowSchemaLister
122: 	plcLister       flowcontrollisters.PriorityLevelConfigurationLister
123: }
124: 
125: func (bce *bootstrapConfigurationEnsurer) ensureAPFBootstrapConfiguration(hookContext genericapiserver.PostStartHookContext) error {
126: 	clientset, err := flowcontrolclient.NewForConfig(hookContext.LoopbackClientConfig)
127: 	if err != nil {
128: 		return fmt.Errorf("failed to initialize clientset for APF - %w", err)
129: 	}
130: 
131: 	err = func() error {
132: 		// get a derived context that gets cancelled after 5m or
133: 		// when the StopCh gets closed, whichever happens first.
134: 		ctx, cancel := contextFromChannelAndMaxWaitDuration(hookContext.Done(), 5*time.Minute)
135: 		defer cancel()
136: 
137: 		if !cache.WaitForCacheSync(ctx.Done(), bce.informersSynced...) {
138: 			return fmt.Errorf("APF bootstrap ensurer timed out waiting for cache sync")
139: 		}
140: 
141: 		err = wait.PollImmediateUntilWithContext(
142: 			ctx,
143: 			time.Second,
144: 			func(context.Context) (bool, error) {
145: 				if err := ensure(ctx, clientset, bce.fsLister, bce.plcLister); err != nil {
146: 					klog.ErrorS(err, "APF bootstrap ensurer ran into error, will retry later")
147: 					return false, nil
148: 				}
149: 				return true, nil
150: 			})
151: 		if err != nil {
152: 			return fmt.Errorf("unable to initialize APF bootstrap configuration: %w", err)
153: 		}
154: 		return nil
155: 	}()
156: 	if err != nil {
157: 		return err
158: 	}
159: 
160: 	// we have successfully initialized the bootstrap configuration, now we
161: 	// spin up a goroutine which reconciles the bootstrap configuration periodically.
162: 	go func() {
163: 		wait.PollImmediateUntil(
164: 			time.Minute,
165: 			func() (bool, error) {
166: 				if err := ensure(hookContext, clientset, bce.fsLister, bce.plcLister); err != nil {
167: 					klog.ErrorS(err, "APF bootstrap ensurer ran into error, will retry later")
168: 				}
169: 				// always auto update both suggested and mandatory configuration
170: 				return false, nil
171: 			}, hookContext.Done())
172: 		klog.Info("APF bootstrap ensurer is exiting")
173: 	}()
174: 
175: 	return nil
176: }
