178: func ensure(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister, plcLister flowcontrollisters.PriorityLevelConfigurationLister) error {
179: 
180: 	if err := ensureSuggestedConfiguration(ctx, clientset, fsLister, plcLister); err != nil {
181: 		// We should not attempt creation of mandatory objects if ensuring the suggested
182: 		// configuration resulted in an error.
183: 		// This only happens when the stop channel is closed.
184: 		return fmt.Errorf("failed ensuring suggested settings - %w", err)
185: 	}
186: 
187: 	if err := ensureMandatoryConfiguration(ctx, clientset, fsLister, plcLister); err != nil {
188: 		return fmt.Errorf("failed ensuring mandatory settings - %w", err)
189: 	}
190: 
191: 	if err := removeDanglingBootstrapConfiguration(ctx, clientset, fsLister, plcLister); err != nil {
192: 		return fmt.Errorf("failed to delete removed settings - %w", err)
193: 	}
194: 
195: 	return nil
196: }
197: 
198: func ensureSuggestedConfiguration(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister, plcLister flowcontrollisters.PriorityLevelConfigurationLister) error {
199: 	plcOps := ensurer.NewPriorityLevelConfigurationOps(clientset.PriorityLevelConfigurations(), plcLister)
200: 	if err := ensurer.EnsureConfigurations(ctx, plcOps, flowcontrolbootstrap.SuggestedPriorityLevelConfigurations, ensurer.NewSuggestedEnsureStrategy[*flowcontrolv1.PriorityLevelConfiguration]()); err != nil {
201: 		return err
202: 	}
203: 
204: 	fsOps := ensurer.NewFlowSchemaOps(clientset.FlowSchemas(), fsLister)
205: 	return ensurer.EnsureConfigurations(ctx, fsOps, flowcontrolbootstrap.SuggestedFlowSchemas, ensurer.NewSuggestedEnsureStrategy[*flowcontrolv1.FlowSchema]())
206: }
207: 
208: func ensureMandatoryConfiguration(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister, plcLister flowcontrollisters.PriorityLevelConfigurationLister) error {
209: 	plcOps := ensurer.NewPriorityLevelConfigurationOps(clientset.PriorityLevelConfigurations(), plcLister)
210: 	if err := ensurer.EnsureConfigurations(ctx, plcOps, flowcontrolbootstrap.MandatoryPriorityLevelConfigurations, ensurer.NewMandatoryEnsureStrategy[*flowcontrolv1.PriorityLevelConfiguration]()); err != nil {
211: 		return err
212: 	}
213: 
214: 	fsOps := ensurer.NewFlowSchemaOps(clientset.FlowSchemas(), fsLister)
215: 	return ensurer.EnsureConfigurations(ctx, fsOps, flowcontrolbootstrap.MandatoryFlowSchemas, ensurer.NewMandatoryEnsureStrategy[*flowcontrolv1.FlowSchema]())
216: }
217: 
218: func removeDanglingBootstrapConfiguration(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister, plcLister flowcontrollisters.PriorityLevelConfigurationLister) error {
219: 	if err := removeDanglingBootstrapFlowSchema(ctx, clientset, fsLister); err != nil {
220: 		return err
221: 	}
222: 
223: 	return removeDanglingBootstrapPriorityLevel(ctx, clientset, plcLister)
224: }
225: 
226: func removeDanglingBootstrapFlowSchema(ctx context.Context, clientset flowcontrolclient.FlowcontrolV1Interface, fsLister flowcontrollisters.FlowSchemaLister) error {
227: 	bootstrap := append(flowcontrolbootstrap.MandatoryFlowSchemas, flowcontrolbootstrap.SuggestedFlowSchemas...)
228: 	fsOps := ensurer.NewFlowSchemaOps(clientset.FlowSchemas(), fsLister)
229: 	return ensurer.RemoveUnwantedObjects(ctx, fsOps, bootstrap)
230: }
