238: // contextFromChannelAndMaxWaitDuration returns a Context that is bound to the
239: // specified channel and the wait duration. The derived context will be
240: // cancelled when the specified channel stopCh is closed or the maximum wait
241: // duration specified in maxWait elapses, whichever happens first.
242: //
243: // Note the caller must *always* call the CancelFunc, otherwise resources may be leaked.
244: func contextFromChannelAndMaxWaitDuration(stopCh <-chan struct{}, maxWait time.Duration) (context.Context, context.CancelFunc) {
245: 	ctx, cancel := context.WithCancel(context.Background())
246: 
247: 	go func() {
248: 		defer cancel()
249: 
250: 		select {
251: 		case <-stopCh:
252: 		case <-time.After(maxWait):
253: 
254: 		// the caller can explicitly cancel the context which is an
255: 		// indication to us to exit the goroutine immediately.
256: 		// Note that we are calling cancel more than once when we are here,
257: 		// CancelFunc is idempotent and we expect no ripple effects here.
258: 		case <-ctx.Done():
259: 		}
260: 	}()
261: 	return ctx, cancel
262: }
